Voici la version **corrigée et complète** de `scrape_convert_dom_to_custom_format.py` avec :

- Chargement du JSON sécurisé.
- Détection du format (`{"objects": [...]}` ou liste brute).
- Appel correct à `build_dom_hierarchy`.

```python
# :FILENAME: scrape_convert_dom_to_custom_format.py
# :DESCRIPTION: Conversion d'un DOM JSON en format d'objets propriétaire enrichis avec hiérarchie
# :INPUT: Chemin vers un fichier JSON exporté depuis le scraper
# :OUTPUT: Chemin vers un fichier JSON converti
# :TAGS: conversion, dom, format, scraper, json, hiérarchie
# :REQUIRES: json, os, uuid
# :RETURNS: (list, str) -> liste d'objets convertis, chemin du fichier sauvegardé

import os
import json
import uuid

def generate_unique_id():
    return uuid.uuid4().hex[:6]

def clean_text(text):
    return text.strip().replace("\n", " ").replace("\t", " ")

def infer_element_type(tag_name):
    if tag_name == "section":
        return "section"
    elif tag_name in ["header", "footer", "nav"]:
        return "layout_block"
    elif tag_name in ["h1", "h2", "h3", "h4", "h5", "h6"]:
        return "title"
    elif tag_name == "p":
        return "text"
    elif tag_name == "a":
        return "link"
    elif tag_name == "img":
        return "image"
    elif tag_name in ["ul", "ol"]:
        return "list"
    elif tag_name == "button":
        return "button"
    elif tag_name == "input":
        return "form_input"
    return "element"

def determine_parent(element, all_elements):
    parent_id = element.get("parent")
    if parent_id and any(e.get("id") == parent_id for e in all_elements):
        return parent_id
    return None

def build_dom_hierarchy(objects):
    by_id = {obj["id"]: obj for obj in objects if isinstance(obj, dict) and "id" in obj}
    children_map = {obj["id"]: [] for obj in objects if isinstance(obj, dict) and "id" in obj}

    for obj in objects:
        parent = obj.get("parent")
        if parent in children_map:
            children_map[parent].append(obj["id"])

    for obj_id, children in children_map.items():
        if "children" not in by_id[obj_id]:
            by_id[obj_id]["children"] = []
        by_id[obj_id]["children"].extend(children)

    return list(by_id.values())

def convert_dom_to_custom_format(dom_json_path):
    print("🔁 Conversion du DOM en format propriétaire...")

    if not os.path.exists(dom_json_path):
        raise FileNotFoundError(f"Fichier introuvable: {dom_json_path}")

    with open(dom_json_path, "r") as f:
        raw_data = json.load(f)
        dom_data = raw_data.get("objects", raw_data)

    if not isinstance(dom_data, list):
        raise TypeError("Le contenu du DOM JSON doit être une liste ou contenir une clé 'objects'")

    enriched = build_dom_hierarchy(dom_data)

    converted = []
    for element in enriched:
        tag = element.get("tag", "div")
        uid = generate_unique_id()
        type_name = infer_element_type(tag)
        name = f"{type_name}_{uid}"

        obj = {
            "name": name,
            "meta": {
                "type": type_name
            },
            "tags": [tag],
            "properties": {
                "html": element.get("html", ""),
                "text": clean_text(element.get("text", "")),
                "attributes": element.get("attributes", {}),
                "css": element.get("css", "")
            },
            "relations": []
        }

        parent_id = determine_parent(element, enriched)
        if parent_id:
            parent_tag = next((e.get("tag", "element") for e in enriched if e.get("id") == parent_id), "element")
            parent_type = infer_element_type(parent_tag)
            obj["relations"].append({
                "name": "parent_of",
                "target": f"{parent_type}_{parent_id[-6:]}"
            })

        converted.append(obj)

    output_path = os.path.join(os.path.dirname(dom_json_path), "converted_dom_output.json")
    with open(output_path, "w") as f:
        json.dump(converted, f, indent=2)

    print(f"✅ {len(converted)} objets extraits du DOM")
    print(f"📁 Résultat sauvegardé dans {os.path.basename(output_path)}")

    return converted, output_path
```

